@RestController
@RequestMapping("/api/meta/excel")
public class ExcelImportController {
    @PostMapping("/import/{modelCode}")
    public ResponseEntity<ExcelImportResult> importExcel(
            @PathVariable String modelCode,
            @RequestParam MultipartFile file,
            @RequestParam(defaultValue = "false") boolean skipErrors,
            @RequestParam(defaultValue = "false") boolean dryRun) {
        ImportOptions options = new ImportOptions();
        options.setSkipErrors(skipErrors);
        options.setDryRun(dryRun);
        ExcelImportResult result = importService.importExcel(modelCode, file.getInputStream(), options);
        return ResponseEntity.ok(result);
    }
}
```

