Create the bitemporal data infrastructure for tracking data changes across two time dimensions.

Create:
1. platform/src/main/java/com/auraboot/module/meta/bitemporal/BitemporalEntity.java
```java
@Data
public abstract class BitemporalEntity {
    private Long id;
    private Long entityKey;       // Logical entity ID (shared across versions)
    private LocalDate validFrom;  // Business validity start
    private LocalDate validTo;    // Business validity end (default: 9999-12-31)
    private Instant txnFrom;      // System recording time
    private Instant txnTo;        // System end time (default: Instant.MAX → DB 'infinity')
    private Long supersededBy;    // ID of the record that superseded this one
    private Long tenantId;

    public boolean isCurrent() {
        return txnTo == null || txnTo.equals(Instant.MAX);
    }

    public static final LocalDate MAX_VALID_DATE = LocalDate.of(9999, 12, 31);
}
```

2. platform/src/main/java/com/auraboot/module/meta/bitemporal/BitemporalRepository.java
```java
@Component
@RequiredArgsConstructor
public class BitemporalRepository {
    private final JdbcTemplate jdbcTemplate;

    /** Find current valid version of an entity */
    public Map<String, Object> findCurrent(String tableName, Long entityKey) {
        String sql = String.format(
            "SELECT * FROM %s WHERE entity_key = ? AND txn_to = 'infinity' AND valid_from <= CURRENT_DATE AND valid_to > CURRENT_DATE AND tenant_id = ?",
            tableName);
        return jdbcTemplate.queryForMap(sql, entityKey, TenantContextHolder.getTenantId());
    }

    /** As-Of query: find state at a specific point in time */
    public Map<String, Object> findAsOf(String tableName, Long entityKey, LocalDate validDate, Instant systemDate) {
        String sql = String.format(
            "SELECT * FROM %s WHERE entity_key = ? AND valid_from <= ? AND valid_to > ? AND txn_from <= ? AND txn_to > ? AND tenant_id = ?",
            tableName);
        return jdbcTemplate.queryForMap(sql, entityKey, validDate, validDate, Timestamp.from(systemDate), Timestamp.from(systemDate), TenantContextHolder.getTenantId());
    }

    /** Correct: end current version and create new version in same transaction */
    @Transactional
    public Long correct(String tableName, Long entityKey, Map<String, Object> correctedData) {
        // 1. End current version
        String endSql = String.format(
            "UPDATE %s SET txn_to = NOW() WHERE entity_key = ? AND txn_to = 'infinity' AND tenant_id = ?",
            tableName);
        jdbcTemplate.update(endSql, entityKey, TenantContextHolder.getTenantId());

        // 2. Insert new version
        correctedData.put("entity_key", entityKey);
        correctedData.put("txn_from", Timestamp.from(Instant.now()));
        correctedData.put("txn_to", "infinity");
        correctedData.put("tenant_id", TenantContextHolder.getTenantId());
        // ... insert using JdbcTemplate
        return insertAndReturnId(tableName, correctedData);
    }

    /** Get full history of an entity */
    public List<Map<String, Object>> findHistory(String tableName, Long entityKey) {
        String sql = String.format(
            "SELECT * FROM %s WHERE entity_key = ? AND tenant_id = ? ORDER BY txn_from ASC",
            tableName);
        return jdbcTemplate.queryForList(sql, entityKey, TenantContextHolder.getTenantId());
    }
}
```

3. platform/src/main/java/com/auraboot/module/meta/bitemporal/BitemporalDdlHelper.java
Helper to generate DDL for bitemporal columns + GiST exclusion constraint:
```java
@Component
public class BitemporalDdlHelper {
    public String generateBitemporalColumns() {
        return """
            entity_key BIGINT NOT NULL,
            valid_from DATE NOT NULL DEFAULT CURRENT_DATE,
            valid_to DATE NOT NULL DEFAULT '9999-12-31',
            txn_from TIMESTAMPTZ NOT NULL DEFAULT NOW(),
            txn_to TIMESTAMPTZ NOT NULL DEFAULT 'infinity',
            superseded_by BIGINT
            """;
    }

    public String generateExclusionConstraint(String tableName) {
        return String.format("""
            ALTER TABLE %s ADD CONSTRAINT %s_no_bitemporal_overlap
            EXCLUDE USING GIST (
                entity_key WITH =,
                tenant_id WITH =,
                daterange(valid_from, valid_to) WITH &&,
                tstzrange(txn_from, txn_to) WITH &&
            )
            """, tableName, tableName);
    }

    public String generateCurrentView(String tableName) {
        return String.format("""
            CREATE OR REPLACE VIEW %s_current AS
            SELECT * FROM %s WHERE txn_to = 'infinity'
            """, tableName, tableName);
    }
}
```

